    const hasCase = (n: number): boolean => stepNames.some((s) => s.includes(`Case ${n}`));
    expect(hasCase(1)).toBe(true);
    expect(hasCase(2)).toBe(true);
    expect(hasCase(3)).toBe(true);
    expect(hasCase(4)).toBe(true);
  });

